// src/index.js - Application entry point demonstrating secure usage of internal and public packages
'use strict';

const dotenv = require('dotenv');

// Load environment variables before anything else
dotenv.config();

const express = require('express');
const helmet = require('helmet');
const cors = require('cors');
const rateLimit = require('express-rate-limit');
const hpp = require('hpp');
const compression = require('compression');
const createError = require('http-errors');

// Internal company packages
const { authenticate, authorize } = require('@company/auth');
const logger = require('@company/logger');
const apiClient = require('@company/api-client');

const app = express();

// Security middleware
app.use(helmet({
  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: ["'self'"],
      styleSrc: ["'self'"],
      imgSrc: ["'self'"],
      connectSrc: ["'self'"],
      fontSrc: ["'self'"],
      objectSrc: ["'none'"],
      mediaSrc: ["'none'"],
      frameSrc: ["'none'"]
    }
  },
  crossOriginEmbedderPolicy: true,
  crossOriginOpenerPolicy: true,
  crossOriginResourcePolicy: { policy: "same-origin" },
  hsts: {
    maxAge: 31536000,
    includeSubDomains: true,
    preload: true
  },
  referrerPolicy: { policy: "strict-origin-when-cross-origin" }
}));

// CORS configuration - restrict to known origins
const allowedOrigins = (process.env.ALLOWED_ORIGINS || '').split(',').filter(Boolean);
app.use(cors({
  origin: function (origin, callback) {
    if (!origin || allowedOrigins.includes(origin)) {
      callback(null, true);
    } else {
      callback(new Error('Not allowed by CORS'));
    }
  },
  methods: ['GET', 'POST', 'PUT', 'DELETE', 'PATCH'],
  allowedHeaders: ['Content-Type', 'Authorization', 'X-Request-ID'],
  credentials: true,
  maxAge: 600
}));

// Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
  skip: (req) => req.path === '/health'
});
app.use(limiter);

// HTTP Parameter Pollution protection
app.use(hpp());

// Compression
app.use(compression());

// Body parsing with size limits
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// Request ID middleware
app.use((req, res, next) => {
  const { v4: uuidv4 } = require('uuid');
  req.requestId = req.headers['x-request-id'] || uuidv4();
  res.setHeader('X-Request-ID', req.requestId);
  next();
});

// Request logging using internal logger
app.use((req, res, next) => {
  const start = Date.now();
  res.on('finish', () => {
    logger.info('request_completed', {
      requestId: req.requestId,
      method: req.method,
      path: req.path,
      statusCode: res.statusCode,
      duration: Date.now() - start,
      userAgent: req.get('user-agent'),
      ip: req.ip
    });
  });
  next();
});

// Health check endpoint (no auth required)
app.get('/health', (req, res) => {
  res.status(200).json({
    status: 'healthy',
    timestamp: new Date().toISOString(),
    uptime: process.uptime()
  });
});

// Readiness check
app.get('/ready', async (req, res) => {
  try {
    // Check connectivity to dependent services via internal api-client
    await apiClient.healthCheck();
    res.status(200).json({ status: 'ready' });
  } catch (error) {
    logger.error('readiness_check_failed', { error: error.message });
    res.status(503).json({ status: 'not_ready' });
  }
});

// Protected routes using internal auth package
app.get('/api/v1/data', authenticate, authorize(['read']), async (req, res, next) => {
  try {
    const data = await apiClient.get('/internal/data', {
      headers: { 'X-Request-ID': req.requestId }
    });
    res.json({ success: true, data });
  } catch (error) {
    next(error);
  }
});

// 404 handler
app.use((req, res, next) => {
  next(createError(404, 'Resource not found'));
});

// Global error handler - never expose internal details
app.use((err, req, res, _next) => {
  const statusCode = err.status || err.statusCode || 500;
  const isProduction = process.env.NODE_ENV === 'production';

  logger.error('unhandled_error', {
    requestId: req.requestId,
    error: err.message,
    stack: err.stack,
    statusCode
  });

  res.status(statusCode).json({
    error: {
      message: statusCode >= 500 && isProduction
        ? 'Internal server error'
        : err.message,
      requestId: req.requestId
    }
  });
});

// Graceful shutdown handling
const PORT = parseInt(process.env.PORT, 10) || 3000;
const HOST = process.env.HOST || '127.0.0.1';

const server = app.listen(PORT, HOST, () => {
  logger.info('server_started', { port: PORT, host: HOST, env: process.env.NODE_ENV });
});

// Set server timeouts
server.keepAliveTimeout = 65000;
server.headersTimeout = 66000;
server.timeout = 30000;

const gracefulShutdown = (signal) => {
  logger.info('shutdown_initiated', { signal });
  server.close(() => {
    logger.info('server_closed', { signal });
    process.exit(0);
  });

  // Force shutdown after 30 seconds
  setTimeout(() => {
    logger.error('forced_shutdown', { signal });
    process.exit(1);
  }, 30000).unref();
};

process.on('SIGTERM', () => gracefulShutdown('SIGTERM'));
process.on('SIGINT', () => gracefulShutdown('SIGINT'));

process.on('unhandledRejection', (reason, promise) => {
  logger.error('unhandled_rejection', {
    reason: reason instanceof Error ? reason.message : String(reason),
    stack: reason instanceof Error ? reason.stack : undefined
  });
});

process.on('uncaughtException', (error) => {
  logger.error('uncaught_exception', {
    error: error.message,
    stack: error.stack
  });
  gracefulShutdown('uncaughtException');
});

module.exports = app;